function solve(n: number, edges: number[][], label: string): number {
    // Build adjacency list
    const adj: number[][] = Array.from({ length: n }, () => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    // Use BFS to find the longest palindrome path
    const visited = new Array(n).fill(false);
    let maxLen = 0;

    // Helper function to check if a string is a palindrome
    function isPalindrome(s: string): boolean {
        return s === s.split('').reverse().join('');
    }

    // DFS to explore all paths
    function dfs(node: number, path: number[], visited: boolean[]): void {
        // Check if current path forms a palindrome
        const currentLabel = path.map(i => label[i]).join('');
        if (isPalindrome(currentLabel)) {
            maxLen = Math.max(maxLen, path.length);
        }

        // Try all neighbors
        for (const neighbor of adj[node]) {
            if (!visited[neighbor]) {
                visited[neighbor] = true;
                path.push(neighbor);
                dfs(neighbor, path, visited);
                path.pop();
                visited[neighbor] = false;
            }
        }
    }

    // Start DFS from each node
    for (let i = 0; i < n; i++) {
        visited[i] = true;
        const path: number[] = [i];
        dfs(i, path, visited);
        visited[i] = false;
    }

    return maxLen;
}

