fn solve(n: i64, edges: Vec<Vec<i64>>, label: String) -> i64 {
    let n = n as usize;
    let mut adj: Vec<Vec<usize>> = vec![vec![]; n];
    for edge in &edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        adj[u].push(v);
        adj[v].push(u);
    }

    let label: Vec<char> = label.chars().collect();
    let mut max_len = 0;

    fn is_palindrome(s: &str) -> bool {
        s == s.chars().rev().collect::<String>()
    }

    fn dfs(node: usize, path: &mut Vec<usize>, visited: &mut Vec<bool>, adj: &Vec<Vec<usize>>, label: &Vec<char>, max_len: &mut i64) {
        let current: String = path.iter().map(|&i| label[i]).collect();
        if is_palindrome(&current) {
            *max_len = std::cmp::max(*max_len, path.len() as i64);
        }

        for &neighbor in &adj[node] {
            if !visited[neighbor] {
                visited[neighbor] = true;
                path.push(neighbor);
                dfs(neighbor, path, visited, adj, label, max_len);
                path.pop();
                visited[neighbor] = false;
            }
        }
    }

    let mut visited = vec![false; n];
    for i in 0..n {
        visited[i] = true;
        let mut path = vec![i];
        dfs(i, &mut path, &mut visited, &adj, &label, &mut max_len);
        visited[i] = false;
    }

    max_len
}
